UPDATE board
SET deleted_at = CURRENT_TIMESTAMP
WHERE board_id = #{boardId}

UPDATE board
SET views = views + 1
WHERE board_id = #{boardId}

UPDATE board
SET is_pinned = NOT is_pinned
WHERE board_id = #{boardId}

UPDATE board_comment
SET deleted_at = CURRENT_TIMESTAMP
WHERE comment_id = #{commentId}
